{
  "name": "AdInsight 360",
  "description": "A comprehensive 360-degree customer insight platform for app distribution advertisers, featuring lifecycle tracking, performance analytics, and AI-driven recommendations."
}

export enum ClientStage {
  PROSPECT = 'PROSPECT', // 拓展期
  ACTIVE = 'ACTIVE',     // 投放期
  CHURN = 'CHURN',       // 流失期
}

export enum Sentiment {
  POSITIVE = 'POSITIVE',
  NEUTRAL = 'NEUTRAL',
  NEGATIVE = 'NEGATIVE',
}

export interface MetricPoint {
  date: string;
  value: number;
  forecast?: number; // Optional forecast value
}

export interface CompetitorData {
  name: string;
  marketShare: number;
  overlap: number; // Percentage of user overlap
}

export interface ClientProfile {
  id: string;
  name: string;
  logo: string;
  industry: string;
  stage: ClientStage;
  apps: string[];
  competitorPlatforms: string[]; // e.g., "Competitor A", "Competitor B"

  // Prospecting Specifics
  bdOwner?: string;
  prospectStage?: 'Lead' | 'Contacted' | 'Meeting' | 'Negotiation' | 'Onboarding';
  lastContactDate?: string;

  // Active Specifics
  totalSpend?: number;
  roi?: number;
  impressions?: number;
  conversions?: number;
  spendTrend?: MetricPoint[];
  conversionTrend?: MetricPoint[];
  competitorAnalysis?: CompetitorData[];

  // Churn Specifics
  churnReason?: string;
  riskScore?: number; // 0-100
  lastActiveDate?: string;
  retentionPlan?: string[];
}

export interface InsightResponse {
  summary: string;
  actionItems: string[];
  prediction?: string;
}

import { GoogleGenAI } from "@google/genai";
import { ClientProfile, InsightResponse } from "../types";

const createClient = () => {
    // In a real scenario, handle potential missing key gracefully in UI
    const apiKey = process.env.API_KEY || ''; 
    return new GoogleGenAI({ apiKey });
}

export const generateClientInsight = async (client: ClientProfile): Promise<InsightResponse> => {
  const ai = createClient();

  const prompt = `
    Analyze the following advertiser client data for an app distribution platform and provide strategic insights.

    Client Context:
    - Name: ${client.name}
    - Industry: ${client.industry}
    - Stage: ${client.stage} (PROSPECT=New Lead, ACTIVE=Running Ads, CHURN=Stopped/At Risk)
    - Key Apps: ${client.apps.join(', ')}
    - Competitor Platforms used: ${client.competitorPlatforms.join(', ')}

    Metrics (if active/churned):
    - Spend: ${client.totalSpend}
    - ROI: ${client.roi}
    - Risk Score: ${client.riskScore || 'N/A'}

    Task:
    1. Provide a 1-sentence executive summary of their status.
    2. List 3 specific action items for the Account Manager or BD.
    3. Provide a brief prediction or strategy tip.

    Return the response as a valid JSON object with keys: "summary", "actionItems" (array of strings), "prediction".
    Do not include markdown formatting like \`\`\`json.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        responseMimeType: 'application/json'
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as InsightResponse;
  } catch (error) {
    console.error("Gemini Insight Error:", error);
    // Fallback mock response if API fails or key is missing
    return {
      summary: "Unable to generate real-time AI insights. Please check API configuration.",
      actionItems: ["Review account manually", "Check competitor activity", "Schedule sync call"],
      prediction: "Data insufficient for AI prediction."
    };
  }
};

import React from 'react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  BarChart,
  Bar,
  AreaChart,
  Area,
} from 'recharts';
import { MetricPoint, CompetitorData } from '../types';

interface TrendChartProps {
  data: MetricPoint[];
  dataKey: string;
  color: string;
  showForecast?: boolean;
}

export const TrendChart: React.FC<TrendChartProps> = ({ data, dataKey, color, showForecast }) => {
  return (
    <ResponsiveContainer width="100%" height={300}>
      <AreaChart data={data} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
        <defs>
          <linearGradient id={`color${dataKey}`} x1="0" y1="0" x2="0" y2="1">
            <stop offset="5%" stopColor={color} stopOpacity={0.8}/>
            <stop offset="95%" stopColor={color} stopOpacity={0}/>
          </linearGradient>
        </defs>
        <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fontSize: 12}} />
        <YAxis axisLine={false} tickLine={false} tick={{fontSize: 12}} />
        <CartesianGrid vertical={false} strokeDasharray="3 3" stroke="#f0f0f0" />
        <Tooltip 
          contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
        />
        <Area 
          type="monotone" 
          dataKey="value" 
          stroke={color} 
          fillOpacity={1} 
          fill={`url(#color${dataKey})`} 
          name="Actual"
        />
        {showForecast && (
             <Area 
             type="monotone" 
             dataKey="forecast" 
             stroke={color} 
             strokeDasharray="5 5"
             fill="none"
             name="Forecast"
           />
        )}
      </AreaChart>
    </ResponsiveContainer>
  );
};

interface CompetitorChartProps {
  data: CompetitorData[];
}

export const CompetitorChart: React.FC<CompetitorChartProps> = ({ data }) => {
  return (
    <ResponsiveContainer width="100%" height={300}>
      <BarChart data={data} layout="vertical" margin={{ top: 10, right: 30, left: 40, bottom: 0 }}>
        <XAxis type="number" hide />
        <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 12}} />
        <Tooltip cursor={{fill: 'transparent'}} />
        <Legend />
        <Bar dataKey="marketShare" name="Market Share %" fill="#8884d8" radius={[0, 4, 4, 0]} barSize={20} />
        <Bar dataKey="overlap" name="User Overlap %" fill="#82ca9d" radius={[0, 4, 4, 0]} barSize={20} />
      </BarChart>
    </ResponsiveContainer>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  Briefcase, 
  Target, 
  TrendingUp, 
  AlertTriangle, 
  Users, 
  BrainCircuit, 
  ArrowRight,
  DollarSign,
  Activity,
  Layers,
  Sparkles
} from 'lucide-react';
import { ClientProfile, ClientStage, InsightResponse } from '../types';
import { TrendChart, CompetitorChart } from './Charts';
import { generateClientInsight } from '../services/geminiService';

interface ClientDetailProps {
  client: ClientProfile;
}

export const ClientDetail: React.FC<ClientDetailProps> = ({ client }) => {
  const [insight, setInsight] = useState<InsightResponse | null>(null);
  const [loadingInsight, setLoadingInsight] = useState(false);

  // Reset insight when client changes
  useEffect(() => {
    setInsight(null);
  }, [client.id]);

  const handleGenerateInsight = async () => {
    setLoadingInsight(true);
    try {
      const data = await generateClientInsight(client);
      setInsight(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingInsight(false);
    }
  };

  const renderHeader = () => (
    <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
      <div className="flex items-center gap-4">
        <img src={client.logo} alt={client.name} className="w-16 h-16 rounded-lg object-cover bg-gray-50" />
        <div>
          <h1 className="text-2xl font-bold text-gray-900">{client.name}</h1>
          <div className="flex items-center gap-2 text-sm text-gray-500 mt-1">
            <span className="flex items-center gap-1"><Briefcase size={14} /> {client.industry}</span>
            <span>•</span>
            <span className="flex items-center gap-1"><Layers size={14} /> {client.apps.length} Apps</span>
          </div>
        </div>
      </div>
      <div className="flex items-center gap-3">
        <span className={`px-4 py-2 rounded-full text-sm font-semibold 
          ${client.stage === ClientStage.ACTIVE ? 'bg-green-100 text-green-700' : 
            client.stage === ClientStage.PROSPECT ? 'bg-blue-100 text-blue-700' : 
            'bg-red-100 text-red-700'}`}>
          {client.stage === ClientStage.PROSPECT && 'Expansion / Prospecting'}
          {client.stage === ClientStage.ACTIVE && 'Active Delivery'}
          {client.stage === ClientStage.CHURN && 'At Risk / Churn'}
        </span>
      </div>
    </div>
  );

  const renderBasicInfo = () => (
    <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 h-full">
      <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center gap-2">
        <Briefcase size={20} className="text-indigo-600"/> Platform Presence
      </h3>
      <div className="space-y-4">
        <div>
          <p className="text-sm text-gray-500">Registered Apps</p>
          <div className="flex flex-wrap gap-2 mt-2">
            {client.apps.map(app => (
              <span key={app} className="px-3 py-1 bg-gray-100 text-gray-700 text-sm rounded-md border border-gray-200">
                {app}
              </span>
            ))}
          </div>
        </div>
        <div>
          <p className="text-sm text-gray-500">Competitor Platforms</p>
          <div className="flex flex-wrap gap-2 mt-2">
            {client.competitorPlatforms.map(comp => (
              <span key={comp} className="px-3 py-1 bg-indigo-50 text-indigo-700 text-sm rounded-md border border-indigo-100">
                {comp}
              </span>
            ))}
          </div>
        </div>
        {client.bdOwner && (
            <div>
                 <p className="text-sm text-gray-500">Responsible BD</p>
                 <p className="font-medium text-gray-900 mt-1">{client.bdOwner}</p>
            </div>
        )}
      </div>
    </div>
  );

  const renderProspectContent = () => {
    const steps = ['Lead', 'Contacted', 'Meeting', 'Negotiation', 'Onboarding'];
    const currentStepIdx = steps.indexOf(client.prospectStage || 'Lead');

    return (
      <div className="space-y-6">
        {/* Pipeline Progress */}
        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
          <h3 className="text-lg font-semibold text-gray-800 mb-6">Expansion Funnel</h3>
          <div className="relative flex items-center justify-between w-full">
            <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-full h-1 bg-gray-200 -z-10" />
            {steps.map((step, idx) => (
              <div key={step} className="flex flex-col items-center bg-white px-2">
                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold mb-2 transition-colors
                  ${idx <= currentStepIdx ? 'bg-blue-600 text-white' : 'bg-gray-200 text-gray-500'}`}>
                  {idx + 1}
                </div>
                <span className={`text-sm ${idx === currentStepIdx ? 'font-bold text-blue-600' : 'text-gray-500'}`}>
                  {step}
                </span>
              </div>
            ))}
          </div>
          <div className="mt-8 p-4 bg-blue-50 rounded-lg border border-blue-100 text-blue-800 text-sm">
            <strong>Next Best Action:</strong> Based on the "Negotiation" stage, schedule a follow-up meeting to discuss the term sheet incentives.
          </div>
        </div>

        {/* BD Info Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
           {renderBasicInfo()}
           <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
             <h3 className="text-lg font-semibold text-gray-800 mb-4">Competitor Intelligence</h3>
             <p className="text-gray-600 mb-4 text-sm">
               This client is heavily investing in <strong>{client.competitorPlatforms[0]}</strong>. 
               Our data suggests their average CPI there is approx $2.50. 
               We can offer a trial package at $2.10 to win share of wallet.
             </p>
             <button className="text-blue-600 font-medium text-sm flex items-center gap-1 hover:underline">
               Download Competitor Report <ArrowRight size={14} />
             </button>
           </div>
        </div>
      </div>
    );
  };

  const renderActiveContent = () => (
    <div className="space-y-6">
      {/* Key Metrics */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
            <div className="text-gray-500 text-sm mb-1">Total Spend (LTV)</div>
            <div className="text-2xl font-bold text-gray-900">${(client.totalSpend || 0).toLocaleString()}</div>
            <div className="text-green-600 text-xs font-medium mt-2 flex items-center">
                <TrendingUp size={12} className="mr-1"/> +12.5% vs last month
            </div>
        </div>
        <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
            <div className="text-gray-500 text-sm mb-1">ROI</div>
            <div className="text-2xl font-bold text-gray-900">{client.roi}x</div>
            <div className="text-gray-400 text-xs font-medium mt-2">Target: 2.0x</div>
        </div>
        <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
            <div className="text-gray-500 text-sm mb-1">Impressions</div>
            <div className="text-2xl font-bold text-gray-900">{(client.impressions || 0 / 1000000).toFixed(1)}M</div>
        </div>
        <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
            <div className="text-gray-500 text-sm mb-1">Conversions</div>
            <div className="text-2xl font-bold text-gray-900">{(client.conversions || 0).toLocaleString()}</div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Main Chart */}
        <div className="lg:col-span-2 bg-white rounded-xl p-6 shadow-sm border border-gray-100">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-lg font-semibold text-gray-800">Spend Trend & Forecast</h3>
            <div className="flex gap-2">
                <span className="flex items-center text-xs text-gray-500"><div className="w-3 h-3 bg-indigo-500 rounded-full mr-1"></div>Actual</span>
                <span className="flex items-center text-xs text-gray-500"><div className="w-3 h-3 border border-indigo-500 border-dashed rounded-full mr-1"></div>Forecast</span>
            </div>
          </div>
          <TrendChart data={client.spendTrend || []} dataKey="spend" color="#6366f1" showForecast={true} />
        </div>

        {/* Competitor Analysis */}
        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
          <h3 className="text-lg font-semibold text-gray-800 mb-6">Market Share</h3>
          <CompetitorChart data={client.competitorAnalysis || []} />
        </div>
      </div>

       <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
           {renderBasicInfo()}
           <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
             <h3 className="text-lg font-semibold text-gray-800 mb-4">Conversion Funnel Analysis</h3>
             <div className="space-y-4">
                <div className="flex justify-between text-sm">
                    <span className="text-gray-600">Impressions</span>
                    <span className="font-medium">100%</span>
                </div>
                <div className="w-full bg-gray-100 rounded-full h-2">
                    <div className="bg-indigo-500 h-2 rounded-full" style={{width: '100%'}}></div>
                </div>

                <div className="flex justify-between text-sm">
                    <span className="text-gray-600">Clicks (CTR 1.2%)</span>
                    <span className="font-medium">1.2%</span>
                </div>
                <div className="w-full bg-gray-100 rounded-full h-2">
                    <div className="bg-indigo-400 h-2 rounded-full" style={{width: '60%'}}></div>
                </div>

                <div className="flex justify-between text-sm">
                    <span className="text-gray-600">Installs (CVR 15%)</span>
                    <span className="font-medium">0.18%</span>
                </div>
                <div className="w-full bg-gray-100 rounded-full h-2">
                    <div className="bg-indigo-300 h-2 rounded-full" style={{width: '30%'}}></div>
                </div>
             </div>
             <p className="mt-4 text-xs text-gray-500">CVR is 5% lower than category benchmark (20%). Recommend optimizing app store page details.</p>
           </div>
       </div>
    </div>
  );

  const renderChurnContent = () => (
    <div className="space-y-6">
      <div className="bg-red-50 border border-red-100 rounded-xl p-6 flex flex-col md:flex-row gap-6 items-start">
        <div className="p-3 bg-white rounded-full shadow-sm text-red-500">
          <AlertTriangle size={32} />
        </div>
        <div className="flex-1">
          <h3 className="text-xl font-bold text-red-800 mb-2">High Churn Risk: {client.riskScore}/100</h3>
          <p className="text-red-700 mb-4">
            Advertiser has stopped spending since {client.lastActiveDate}. 
            Primary reason identified: <strong>{client.churnReason}</strong>.
          </p>
          <div className="bg-white/60 rounded-lg p-4">
            <h4 className="font-semibold text-red-800 mb-2">Recommended Recovery Actions:</h4>
            <ul className="list-disc list-inside space-y-1 text-sm text-red-800">
              {client.retentionPlan?.map((plan, i) => (
                <li key={i}>{plan}</li>
              ))}
            </ul>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white rounded-xl p-6 shadow-sm border border-gray-100">
            <h3 className="text-lg font-semibold text-gray-800 mb-4">Decline Analysis (Last 6 Months)</h3>
            <TrendChart data={client.spendTrend || []} dataKey="churn" color="#ef4444" />
        </div>
        {renderBasicInfo()}
      </div>
    </div>
  );

  return (
    <div className="max-w-7xl mx-auto pb-12">
      {renderHeader()}

      {/* Insight Section - Always Visible if generated */}
      <div className="mb-8">
        {!insight ? (
          <button 
            onClick={handleGenerateInsight}
            disabled={loadingInsight}
            className="flex items-center gap-2 bg-gradient-to-r from-violet-600 to-indigo-600 text-white px-5 py-3 rounded-lg shadow-md hover:shadow-lg transition-all disabled:opacity-70"
          >
            {loadingInsight ? (
               <>Processing AI Analysis...</>
            ) : (
               <><Sparkles size={18} /> Generate AI Strategic Insight</>
            )}
          </button>
        ) : (
          <div className="bg-gradient-to-r from-violet-50 to-indigo-50 border border-indigo-100 rounded-xl p-6 relative overflow-hidden">
             <div className="absolute top-0 right-0 p-4 opacity-10 text-indigo-900">
                <BrainCircuit size={120} />
             </div>
             <h3 className="text-lg font-bold text-indigo-900 mb-3 flex items-center gap-2">
                <Sparkles size={18} className="text-indigo-600"/> AI Strategic Analysis
             </h3>
             <p className="text-indigo-800 font-medium mb-4">{insight.summary}</p>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">Action Items</h4>
                    <ul className="space-y-2">
                        {insight.actionItems.map((item, i) => (
                            <li key={i} className="flex items-start gap-2 text-sm text-indigo-900">
                                <span className="mt-1 w-1.5 h-1.5 bg-indigo-500 rounded-full flex-shrink-0"></span>
                                {item}
                            </li>
                        ))}
                    </ul>
                </div>
                <div>
                    <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">AI Prediction</h4>
                    <p className="text-sm text-indigo-900 italic">"{insight.prediction}"</p>
                </div>
             </div>
             <button onClick={() => setInsight(null)} className="mt-4 text-xs text-indigo-500 hover:text-indigo-700 underline">Refresh Analysis</button>
          </div>
        )}
      </div>

      {client.stage === ClientStage.PROSPECT && renderProspectContent()}
      {client.stage === ClientStage.ACTIVE && renderActiveContent()}
      {client.stage === ClientStage.CHURN && renderChurnContent()}
    </div>
  );
};

import React, { useState } from 'react';
import { LayoutDashboard, Users, Settings, PieChart, Menu, X } from 'lucide-react';
import { MOCK_CLIENTS } from './constants';
import { ClientDetail } from './components/ClientDetail';
import { ClientStage } from './types';

const App: React.FC = () => {
  const [selectedClientId, setSelectedClientId] = useState<string>(MOCK_CLIENTS[0].id);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const selectedClient = MOCK_CLIENTS.find(c => c.id === selectedClientId) || MOCK_CLIENTS[0];

  return (
    <div className="flex h-screen bg-gray-50 text-gray-900 font-sans overflow-hidden">
      {/* Sidebar */}
      <div className={`${sidebarOpen ? 'w-64' : 'w-20'} bg-slate-900 text-white transition-all duration-300 flex-shrink-0 flex flex-col`}>
        <div className="p-5 flex items-center justify-between border-b border-slate-700">
          <div className={`font-bold text-lg flex items-center gap-2 ${!sidebarOpen && 'hidden'}`}>
             <div className="w-8 h-8 bg-blue-500 rounded-lg flex items-center justify-center">AI</div>
             AdInsight
          </div>
          <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-1 hover:bg-slate-700 rounded text-slate-400">
            {sidebarOpen ? <X size={20} /> : <Menu size={20} />}
