             </button>
             <button className="w-full flex items-center gap-3 px-3 py-2 bg-blue-600 text-white rounded-lg transition-colors">
                <Users size={20} />
                {sidebarOpen && <span>Clients</span>}
             </button>
             <button className="w-full flex items-center gap-3 px-3 py-2 text-slate-300 hover:bg-slate-800 hover:text-white rounded-lg transition-colors">
                <PieChart size={20} />
                {sidebarOpen && <span>Reports</span>}
             </button>
             <button className="w-full flex items-center gap-3 px-3 py-2 text-slate-300 hover:bg-slate-800 hover:text-white rounded-lg transition-colors">
                <Settings size={20} />
                {sidebarOpen && <span>Settings</span>}
             </button>
           </nav>

           <div className="mt-8 px-4 mb-2 text-xs font-semibold text-slate-500 uppercase tracking-wider">Select Client (Demo)</div>
           <div className="px-2 space-y-2">
              {MOCK_CLIENTS.map(client => (
                  <button 
                    key={client.id}
