                    `}
                  >
                    <div className={`w-2 h-2 rounded-full flex-shrink-0 
                        ${client.stage === ClientStage.ACTIVE ? 'bg-green-500' : 
                          client.stage === ClientStage.PROSPECT ? 'bg-blue-400' : 'bg-red-500'}`} 
                    />
                    {sidebarOpen && (
                        <div className="truncate">
                            <div className="text-sm font-medium">{client.name}</div>
                            <div className="text-xs opacity-60 truncate">{client.industry}</div>
                        </div>
                    )}
                  </button>
              ))}
           </div>
