import { GoogleGenAI, Type } from "@google/genai";
import { ClientProfile, InsightResponse } from "../types";

// Always use process.env.API_KEY directly for initialization
const createClient = () => {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
}

export const generateClientInsight = async (client: ClientProfile): Promise<InsightResponse> => {
  const ai = createClient();

  // Updated prompt to use existing properties: store_intel?.competitor_sdk_presence and health_score
  const prompt = `
    请作为应用分发平台的资深广告专家，分析以下广告主客户数据，并提供中文战略洞察。

    客户背景:
    - 名称: ${client.name}
    - 行业: ${client.industry}
    - 阶段: ${client.stage} (PROSPECT=拓展期线索, ACTIVE=投放中, CHURN=流失/风险)
    - 关键应用: ${client.apps.join(', ')}
    - 竞品平台使用情况: ${(client.store_intel?.competitor_sdk_presence || []).join(', ')}

    指标数据 (若为投放期/流失期):
    - 总消耗: ${client.totalSpend || 0}
    - ROI: ${client.roi || 0}
    - 健康评分: ${client.health_score}

    任务:
    1. 提供 1 句高管摘要，概括客户当前状态。
    2. 列出 3 项具体的行动建议 (Action Items)，供客户经理或商务 BD 执行。
    3. 提供一个简短的预测或战略提示。

    请以 JSON 格式返回。
    所有内容必须使用中文。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        // Recommended way to configure expected output using responseSchema
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            actionItems: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            prediction: { type: Type.STRING }
          },
          required: ["summary", "actionItems", "prediction"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as InsightResponse;
  } catch (error) {
    console.error("Gemini Insight Error:", error);
    // Fallback mock response if API fails or key is missing
    return {
      summary: "无法生成实时 AI 洞察。请检查您的网络连接或 API 配置。",
      actionItems: ["人工审查账户状态", "检查竞品活动", "安排同步会议"],
      prediction: "基于现有指标，该账户近期表现平稳，需关注素材迭代。"
    };
  }
};

